// Ref: #/components/schemas/TieringStatus
type TieringStatus struct {
	Mode        TieringMode       `json:"mode"`
	PauseState  TieringPauseState `json:"pauseState"`
	PauseReason OptString         `json:"pauseReason"`
	// Movoor's intent-level "active now": convergence legs currently
	// executing, spanning the whole dispatch-to-converged window rather
	// than the brief moment the physical operation is visible in
	// system.moves/system.merges.
	InFlight []TieringInFlightLeg `json:"inFlight"`
	// Concurrent leg cap per node (nodes own independent disks and do not starve each other);
	// maxBytesInFlight is the aggregate ceiling.
	MaxConcurrentPartitions int          `json:"maxConcurrentPartitions"`
	MaxMovesPerCycle        int          `json:"maxMovesPerCycle"`
	MaxBytesInFlight        UInt64String `json:"maxBytesInFlight"`
	BytesInFlight           UInt64String `json:"bytesInFlight"`
	MaxBytesPerDay          UInt64String `json:"maxBytesPerDay"`
	BytesMovedToday         UInt64String `json:"bytesMovedToday"`
	UpdatedAt               time.Time    `json:"updatedAt"`
}

